import React, { useState, useRef, useCallback, useEffect } from 'react';
import './Canvas.css';
import { Sparkles, Package, Settings, Upload, Plus, Minus, Palette, ZoomIn, ZoomOut } from 'lucide-react';
import ComponentModal from './ComponentModal';
import GeneratedComponent from './GeneratedComponent';
import DesignSystemModal from './DesignSystemModal';
import SettingsModal from './SettingsModal';
import { aiService } from '../services/aiService';
import { userService } from '../services/userService';

// Updated Component interface with frame support
interface Component {
  id: string;
  code: string;
  prompt: string;
  position: { x: number; y: number };
  size: { width: number; height: number };
  activeBreakpoint: 'mobile' | 'tablet' | 'desktop';
  breakpointSizes: {
    mobile: { width: number; height: number };
    tablet: { width: number; height: number };
    desktop: { width: number; height: number };
  };
}

interface FrameComponent extends Component {
  frameTitle: string;
  isSelected: boolean;
}

const Canvas: React.FC = () => {
  const [zoom, setZoom] = useState(100);
  const [canvasPosition, setCanvasPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [isSpacePressed, setIsSpacePressed] = useState(false);
  const [canvasColor, setCanvasColor] = useState('#ffffff');
  const [showDots, setShowDots] = useState(true);
  const [showColorPicker, setShowColorPicker] = useState(false);
  const [showComponentModal, setShowComponentModal] = useState(false);
  const [showComponentDropdown, setShowComponentDropdown] = useState(false);
  const [showDesignSystemModal, setShowDesignSystemModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [components, setComponents] = useState<Component[]>([]);
  const [selectedComponentId, setSelectedComponentId] = useState<string | null>(null);
  const [editingComponent, setEditingComponent] = useState<string | null>(null);
  const [designSystem, setDesignSystem] = useState('No design system');
  const canvasRef = useRef<HTMLDivElement>(null);
  const dragStart = useRef({ x: 0, y: 0 });
  const colorPickerRef = useRef<HTMLDivElement>(null);

  // Pan state
  const [isPanning, setIsPanning] = useState(false);
  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
  const [panOffset, setPanOffset] = useState({ x: 0, y: 0 });

  const handleZoomIn = () => {
    setZoom(prev => Math.min(prev + 10, 200));
  };

  const handleZoomOut = () => {
    setZoom(prev => Math.max(prev - 10, 10));
  };

  const toggleColorPicker = () => {
    setShowColorPicker(prev => !prev);
  };

  const toggleDots = () => {
    setShowDots(prev => !prev);
  };

  const handleAddComponent = () => {
    setEditingComponent(null);
    setShowComponentModal(true);
  };

  const generateComponentCode = async (prompt: string): Promise<string> => {
    // Simulate AI generation with example components
    const exampleComponents = {
      'sign in card': `
        <div style="
          max-width: 400px;
          padding: 32px;
          background: #ffffff;
          border-radius: 12px;
          box-shadow: 0 8px 32px rgba(0,0,0,0.1);
          border: 1px solid #e5e7eb;
        ">
          <h2 style="margin: 0 0 8px 0; font-size: 24px; font-weight: 600; color: #111827;">Welcome back</h2>
          <p style="margin: 0 0 24px 0; color: #6b7280; font-size: 14px;">Sign in to your account to continue</p>
          <form>
            <div style="margin-bottom: 16px;">
              <label style="display: block; margin-bottom: 6px; font-size: 14px; font-weight: 500; color: #374151;">Email</label>
              <input type="email" placeholder="Enter your email" style="
                width: 100%;
                padding: 12px 16px;
                border: 1px solid #d1d5db;
                border-radius: 8px;
                font-size: 14px;
                outline: none;
                box-sizing: border-box;
              " />
            </div>
            <div style="margin-bottom: 24px;">
              <label style="display: block; margin-bottom: 6px; font-size: 14px; font-weight: 500; color: #374151;">Password</label>
              <input type="password" placeholder="Enter your password" style="
                width: 100%;
                padding: 12px 16px;
                border: 1px solid #d1d5db;
                border-radius: 8px;
                font-size: 14px;
                outline: none;
                box-sizing: border-box;
              " />
            </div>
            <button type="submit" style="
              width: 100%;
              padding: 12px;
              background: #3b82f6;
              color: white;
              border: none;
              border-radius: 8px;
              font-size: 14px;
              font-weight: 500;
              cursor: pointer;
              margin-bottom: 16px;
            ">Sign In</button>
          </form>
          <p style="text-align: center; color: #6b7280; font-size: 14px; margin: 0;">
            Don't have an account? <a href="#" style="color: #3b82f6; text-decoration: none;">Sign up</a>
          </p>
        </div>
      `,
      'pricing card': `
        <div style="
          max-width: 320px;
          padding: 32px 24px;
          background: #ffffff;
          border-radius: 16px;
          box-shadow: 0 8px 32px rgba(0,0,0,0.1);
          border: 2px solid #e5e7eb;
          text-align: center;
        ">
          <h3 style="margin: 0 0 8px 0; font-size: 20px; font-weight: 600; color: #111827;">Pro Plan</h3>
          <p style="margin: 0 0 24px 0; color: #6b7280; font-size: 14px;">Perfect for growing teams</p>
          <div style="margin-bottom: 24px;">
            <span style="font-size: 48px; font-weight: 700; color: #111827;">$29</span>
            <span style="color: #6b7280; font-size: 16px;">/month</span>
          </div>
          <ul style="list-style: none; padding: 0; margin: 0 0 32px 0; text-align: left;">
            <li style="padding: 8px 0; color: #374151; font-size: 14px;">✓ Unlimited projects</li>
            <li style="padding: 8px 0; color: #374151; font-size: 14px;">✓ Advanced analytics</li>
            <li style="padding: 8px 0; color: #374151; font-size: 14px;">✓ Priority support</li>
            <li style="padding: 8px 0; color: #374151; font-size: 14px;">✓ Custom integrations</li>
          </ul>
          <button style="
            width: 100%;
            padding: 12px;
            background: #3b82f6;
            color: white;
            border: none;
            border-radius: 8px;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
          ">Get Started</button>
        </div>
      `,
      'music player card': `
        <div style="
          width: 320px;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          border-radius: 20px;
          padding: 24px;
          color: white;
          box-shadow: 0 20px 40px rgba(0,0,0,0.3);
        ">
          <div style="text-align: center; margin-bottom: 20px;">
            <div style="
              width: 120px;
              height: 120px;
              background: rgba(255,255,255,0.2);
              border-radius: 16px;
              margin: 0 auto 16px;
              display: flex;
              align-items: center;
              justify-content: center;
              font-size: 48px;
            ">🎵</div>
            <h3 style="margin: 0 0 4px 0; font-size: 18px; font-weight: 600;">Bohemian Rhapsody</h3>
            <p style="margin: 0; opacity: 0.8; font-size: 14px;">Queen</p>
          </div>
          <div style="margin-bottom: 20px;">
            <div style="height: 4px; background: rgba(255,255,255,0.3); border-radius: 2px; margin-bottom: 8px;">
              <div style="width: 60%; height: 100%; background: white; border-radius: 2px;"></div>
            </div>
            <div style="display: flex; justify-content: space-between; font-size: 12px; opacity: 0.8;">
              <span>2:45</span>
              <span>5:55</span>
            </div>
          </div>
          <div style="display: flex; justify-content: center; align-items: center; gap: 20px;">
            <button style="background: none; border: none; color: white; font-size: 20px; cursor: pointer;">⏮️</button>
            <button style="
              background: white;
              border: none;
              color: #667eea;
              width: 48px;
              height: 48px;
              border-radius: 50%;
              font-size: 16px;
              cursor: pointer;
              display: flex;
              align-items: center;
              justify-content: center;
            ">▶️</button>
            <button style="background: none; border: none; color: white; font-size: 20px; cursor: pointer;">⏭️</button>
          </div>
        </div>
      `
    };

    // Return example component or default
    const normalizedPrompt = prompt.toLowerCase();
    for (const [key, code] of Object.entries(exampleComponents)) {
      if (normalizedPrompt.includes(key.split(' ')[0])) {
        return code;
      }
    }

    // Default component
    return `
      <div style="
        padding: 24px;
        background: #ffffff;
        border-radius: 12px;
        box-shadow: 0 4px 16px rgba(0,0,0,0.1);
        border: 1px solid #e5e7eb;
        max-width: 300px;
      ">
        <h3 style="margin: 0 0 12px 0; color: #111827; font-size: 18px; font-weight: 600;">Generated Component</h3>
        <p style="margin: 0; color: #6b7280; font-size: 14px; line-height: 1.5;">
          This component was generated from: "${prompt}"
        </p>
      </div>
    `;
  };

  const handleGenerateComponent = async (prompt: string) => {
    // Check usage limits
    const usageCheck = userService.canGenerateComponent();
    if (!usageCheck.allowed) {
      alert(usageCheck.reason);
      return;
    }

    try {
      // Get user settings for AI service
      const userSettings = userService.getUserSettings();

      // Generate component using AI service
      const generationRequest = {
        prompt,
        designSystem: designSystem !== 'No design system' ? designSystem : undefined,
        userTier: {
          type: userSettings.tier,
          apiKey: userSettings.apiKey
        }
      };

      const response = await aiService.generateComponent(generationRequest);

      // Combine HTML and CSS into a single code string
      const code = `${response.html}\n<style>\n${response.css}\n</style>`;

      // Increment usage counter
      userService.incrementUsage();

      if (editingComponent) {
        // Update existing component
        setComponents(prev => prev.map(comp => 
          comp.id === editingComponent 
            ? { ...comp, code, prompt }
            : comp
        ));
        setEditingComponent(null);
      } else {
        // Create new component with responsive frame
        const newComponent: Component = {
          id: Date.now().toString(),
          code,
          prompt,
          position: { 
            x: 100 + (components.length * 50), 
            y: 100 + (components.length * 50) 
          },
          size: { width: 300, height: 200 },
          activeBreakpoint: 'desktop',
          breakpointSizes: {
            mobile: { width: 375, height: 600 },
            tablet: { width: 768, height: 900 },
            desktop: { width: 1200, height: 700 }
          }
        };
        setComponents(prev => [...prev, newComponent]);
        setSelectedComponentId(newComponent.id);
      }

      // Close modal
      setShowComponentModal(false);
    } catch (error) {
      console.error('Component generation failed:', error);
      alert('Failed to generate component. Please check your settings or try again.');
    }
  };

  const handleEditComponent = (componentId: string) => {
    setEditingComponent(componentId);
    setSelectedComponentId(componentId);
    setShowComponentModal(true);
  };

  const handleDeleteComponent = (componentId: string) => {
    setComponents(prev => prev.filter(comp => comp.id !== componentId));
    if (selectedComponentId === componentId) {
      setSelectedComponentId(null);
    }
  };

  const handleDuplicateComponent = (componentId: string) => {
    const component = components.find(comp => comp.id === componentId);
    if (component) {
      const newComponent: Component = {
        ...component,
        id: Date.now().toString(),
        position: { 
          x: component.position.x + 30, 
          y: component.position.y + 30 
        }
      };
      setComponents(prev => [...prev, newComponent]);
      setSelectedComponentId(newComponent.id);
    }
  };

  const handleSelectComponent = (id: string) => {
    setSelectedComponentId(id);
  };

  const handleMoveComponent = (id: string, x: number, y: number) => {
    setComponents(prev => prev.map(comp => 
      comp.id === id ? { ...comp, position: { x, y } } : comp
    ));
  };

  const handleResizeComponent = (id: string, width: number, height: number) => {
    setComponents(prev => prev.map(comp => {
      if (comp.id === id) {
        const updatedSizes = {
          ...comp.breakpointSizes,
          [comp.activeBreakpoint]: { width, height }
        };
        return { 
          ...comp, 
          size: { width, height },
          breakpointSizes: updatedSizes
        };
      }
      return comp;
    }));
  };

  // Handle breakpoint switching
  const handleBreakpointChange = (componentId: string, breakpoint: 'mobile' | 'tablet' | 'desktop') => {
    setComponents(prev => prev.map(comp => {
      if (comp.id === componentId) {
        const newSize = comp.breakpointSizes[breakpoint];
        return {
          ...comp,
          activeBreakpoint: breakpoint,
          size: newSize
        };
      }
      return comp;
    }));
  };

  // Deselect component when clicking on canvas
  const handleCanvasClick = (e: React.MouseEvent) => {
    if (e.target === canvasRef.current || e.target === e.currentTarget) {
      setSelectedComponentId(null);
      setShowComponentDropdown(false);
    }
  };

  // Handle double-click to open component modal
  const handleCanvasDoubleClick = (e: React.MouseEvent) => {
    if (e.target === canvasRef.current || e.target === e.currentTarget) {
      setShowComponentModal(true);
    }
  };

  const handleColorChange = (color: string) => {
    setCanvasColor(color);
  };

  const handleGradientClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    const hue = x * 360;
    const saturation = 100;
    const value = (1 - y) * 100;

    const color = hsvToHex(hue, saturation, value);
    setCanvasColor(color);
  };

  const handleHueClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const hue = x * 360;

    const color = hsvToHex(hue, 100, 100);
    setCanvasColor(color);
  };

  const hsvToHex = (h: number, s: number, v: number): string => {
    h = h / 360;
    s = s / 100;
    v = v / 100;

    const c = v * s;
    const x = c * (1 - Math.abs((h * 6) % 2 - 1));
    const m = v - c;

    let r = 0, g = 0, b = 0;

    if (0 <= h && h < 1/6) {
      r = c; g = x; b = 0;
    } else if (1/6 <= h && h < 2/6) {
      r = x; g = c; b = 0;
    } else if (2/6 <= h && h < 3/6) {
      r = 0; g = c; b = x;
    } else if (3/6 <= h && h < 4/6) {
      r = 0; g = x; b = c;
    } else if (4/6 <= h && h < 5/6) {
      r = x; g = 0; b = c;
    } else if (5/6 <= h && h < 1) {
      r = c; g = 0; b = x;
    }

    r = Math.round((r + m) * 255);
    g = Math.round((g + m) * 255);
    b = Math.round((b + m) * 255);

    return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`;
  };

  // Pan and keyboard controls
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (!target.closest('.color-picker-container')) {
        setShowColorPicker(false);
      }
      if (!target.closest('.component-dropdown')) {
        setShowComponentDropdown(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        setIsSpacePressed(true);
      }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') {
        e.preventDefault();
        setIsSpacePressed(false);
        setIsPanning(false);
      }
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (isSpacePressed && e.target === canvasRef.current) {
        setIsPanning(true);
        setPanStart({ x: e.clientX - panOffset.x, y: e.clientY - panOffset.y });
      }
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (isPanning && isSpacePressed) {
        setPanOffset({
          x: e.clientX - panStart.x,
          y: e.clientY - panStart.y
        });
      }
    };

    const handleMouseUp = () => {
      setIsPanning(false);
    };

    document.addEventListener('keydown', handleKeyDown);
    document.addEventListener('keyup', handleKeyUp);
    document.addEventListener('mousedown', handleMouseDown);
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.removeEventListener('keyup', handleKeyUp);
      document.removeEventListener('mousedown', handleMouseDown);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isSpacePressed, isPanning, panStart, panOffset]);

  return (
    <div className="canvas-container">
      {/* Top Controls */}
      <div className="canvas-controls">
        <div className="zoom-controls">
          <button className="control-btn" onClick={handleZoomOut}>
            <ZoomOut size={16} />
          </button>
          <span className="zoom-level">{zoom}%</span>
          <button className="control-btn" onClick={handleZoomIn}>
            <ZoomIn size={16} />
          </button>
        </div>

        <div className="canvas-actions">
          <div className="color-picker-container">
            <button 
              className={`control-btn ${showColorPicker ? 'active' : ''}`}
              onClick={toggleColorPicker}
            >
              <Palette size={16} />
            </button>

            {showColorPicker && (
              <div className="color-picker">
                <div className="color-gradient" onClick={handleGradientClick}>
                  <div 
                    className="color-gradient-bg"
                    style={{
                      background: `linear-gradient(to bottom, 
                        hsl(${canvasColor.slice(1)}, 100%, 50%) 0%, 
                        transparent 100%), 
                        linear-gradient(to right, 
                        white 0%, 
                        transparent 100%)`
                    }}
                  />
                </div>
                <div className="hue-slider" onClick={handleHueClick}>
                  <div className="hue-slider-bg" />
                </div>
                <div className="color-inputs">
                  <input
                    type="text"
                    value={canvasColor}
                    onChange={(e) => handleColorChange(e.target.value)}
                    className="hex-input"
                    placeholder="#ffffff"
                  />
                  <div 
                    className="color-preview"
                    style={{ backgroundColor: canvasColor }}
                  />
                </div>
                <div className="texture-controls">
                  <label className="texture-toggle">
                    <input
                      type="checkbox"
                      checked={showDots}
                      onChange={toggleDots}
                    />
                    <span>Dotted texture</span>
                  </label>
                </div>
              </div>
            )}
          </div>

          <button className="control-btn" onClick={() => setShowSettingsModal(true)}>
            <Settings size={16} />
          </button>
        </div>
      </div>

      {/* Canvas */}
      <div 
        ref={canvasRef}
        className={`canvas ${isSpacePressed ? 'panning' : ''}`}
        style={{
          backgroundColor: canvasColor,
          transform: `scale(${zoom / 100}) translate(${panOffset.x}px, ${panOffset.y}px)`,
          transformOrigin: '0 0'
        }}
        onClick={handleCanvasClick}
        onDoubleClick={handleCanvasDoubleClick}
      >
        {/* Dotted background */}
        {showDots && (
          <div 
            className="canvas-dots"
            style={{
              backgroundImage: `radial-gradient(circle, rgba(0,0,0,0.1) 1px, transparent 1px)`,
              backgroundSize: '20px 20px'
            }}
          />
        )}

        {/* Add Component Button */}
        <button className="add-component-btn" onClick={handleAddComponent}>
          <Plus size={20} />
          <span>Create Component</span>
        </button>

        {/* Render Components as Interactive Frames */}
        {components.map((component) => (
          <InteractiveFrame
            key={component.id}
            component={component}
            isSelected={selectedComponentId === component.id}
            onSelect={handleSelectComponent}
            onMove={handleMoveComponent}
            onResize={handleResizeComponent}
            onEdit={handleEditComponent}
            onDelete={handleDeleteComponent}
            onDuplicate={handleDuplicateComponent}
            onBreakpointChange={handleBreakpointChange}
          />
        ))}
      </div>

      {/* Modals */}
      <ComponentModal
        isOpen={showComponentModal}
        onClose={() => setShowComponentModal(false)}
        onGenerate={handleGenerateComponent}
        editingComponent={editingComponent ? {
          id: editingComponent,
          prompt: components.find(c => c.id === editingComponent)?.prompt || ''
        } : null}
      />

      <SettingsModal
        isOpen={showSettingsModal}
        onClose={() => setShowSettingsModal(false)}
      />
    </div>
  );
};

// Interactive Frame Component
interface InteractiveFrameProps {
  component: Component;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onResize: (id: string, width: number, height: number) => void;
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
  onDuplicate: (id: string) => void;
  onBreakpointChange: (id: string, breakpoint: 'mobile' | 'tablet' | 'desktop') => void;
}

const InteractiveFrame: React.FC<InteractiveFrameProps> = ({
  component,
  isSelected,
  onSelect,
  onMove,
  onResize,
  onEdit,
  onDelete,
  onDuplicate,
  onBreakpointChange
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [showContextMenu, setShowContextMenu] = useState(false);
  const [contextMenuPosition, setContextMenuPosition] = useState({ x: 0, y: 0 });

  const frameRef = useRef<HTMLDivElement>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (e.button === 2) return; // Right click

    e.stopPropagation();
    onSelect(component.id);

    setIsDragging(true);
    setDragStart({
      x: e.clientX - component.position.x,
      y: e.clientY - component.position.y
    });
  };

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    onSelect(component.id);
    setContextMenuPosition({ x: e.clientX, y: e.clientY });
    setShowContextMenu(true);
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging && !isResizing) {
        onMove(
          component.id,
          e.clientX - dragStart.x,
          e.clientY - dragStart.y
        );
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      setIsResizing(false);
    };

    const handleClickOutside = () => {
      setShowContextMenu(false);
    };

    if (isDragging) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    }

    document.addEventListener('click', handleClickOutside);

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.removeEventListener('click', handleClickOutside);
    };
  }, [isDragging, isResizing, dragStart, component.id, onMove]);

  return (
    <>
      <div
        ref={frameRef}
        className={`interactive-frame ${isSelected ? 'selected' : ''}`}
        style={{
          left: component.position.x,
          top: component.position.y,
          width: component.size.width,
          height: component.size.height
        }}
        onMouseDown={handleMouseDown}
        onContextMenu={handleContextMenu}
      >
        {/* Frame Header */}
        <div className="frame-header">
          <div className="frame-title">
            <span className="frame-name">
              {component.prompt.substring(0, 30)}
              {component.prompt.length > 30 ? '...' : ''}
            </span>
            <div className="breakpoint-indicators">
              <button
                className={`breakpoint-btn ${component.activeBreakpoint === 'mobile' ? 'active' : ''}`}
                onClick={() => onBreakpointChange(component.id, 'mobile')}
                title="Mobile View"
              >
                📱
              </button>
              <button
                className={`breakpoint-btn ${component.activeBreakpoint === 'tablet' ? 'active' : ''}`}
                onClick={() => onBreakpointChange(component.id, 'tablet')}
                title="Tablet View"
              >
                💻
              </button>
              <button
                className={`breakpoint-btn ${component.activeBreakpoint === 'desktop' ? 'active' : ''}`}
                onClick={() => onBreakpointChange(component.id, 'desktop')}
                title="Desktop View"
              >
                🖥️
              </button>
            </div>
          </div>
        </div>

        {/* Component Content */}
        <div className="frame-content">
          <GeneratedComponent
            id={component.id}
            code={component.code}
            isSelected={isSelected}
            onSelect={onSelect}
            onMove={() => {}}
            onResize={(width, height) => onResize(component.id, width, height)}
          />
        </div>

        {/* Resize Handles */}
        {isSelected && (
          <>
            <div className="resize-handle nw" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle ne" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle sw" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle se" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle n" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle s" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle w" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
            <div className="resize-handle e" onMouseDown={(e) => { e.stopPropagation(); setIsResizing(true); }} />
          </>
        )}
      </div>

      {/* Context Menu */}
      {showContextMenu && (
        <div
          className="context-menu"
          style={{
            left: contextMenuPosition.x,
            top: contextMenuPosition.y
          }}
        >
          <button onClick={() => { onEdit(component.id); setShowContextMenu(false); }}>
            Edit Component
          </button>
          <button onClick={() => { onDuplicate(component.id); setShowContextMenu(false); }}>
            Duplicate
          </button>
          <button onClick={() => { onDelete(component.id); setShowContextMenu(false); }}>
            Delete
          </button>
        </div>
      )}
    </>
  );
};

export default Canvas;
